import{c as t,Q as a,j as i,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I invite a user to my customer?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/invite-user.md","filePath":"guide/recipes/portal/invite-user.md","lastUpdated":1779094756000}'),o={name:"guide/recipes/portal/invite-user.md"};function s(n,e,l,c,d,u){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="how-do-i-invite-a-user-to-my-customer" tabindex="-1">How do I invite a user to my customer? <a class="header-anchor" href="#how-do-i-invite-a-user-to-my-customer" aria-label="Permalink to &quot;How do I invite a user to my customer?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>You can add a new person to your customer by inviting them by email. They receive a link that walks them through verification and setting up their account.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Users</strong> in the sidebar.</li><li>Click <strong>Invite Users</strong> (top right).</li><li>Type or paste the email address. Add more by pressing <strong>Enter</strong> between each one — you can also paste a list like <code>Jane Doe &lt;jane@example.com&gt;</code> and we&#39;ll split the name and email automatically.</li><li>Click <strong>Next</strong>.</li><li>On the review step, set each person&#39;s <strong>portal role</strong> (Admin, Billing, Viewer, or Member) and fix any first/last name we couldn&#39;t infer.</li><li>Click <strong>Send Invites</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>Each invitee receives an email with a verification link. Until they accept, they appear in the Users table with status <strong>Invited</strong>. You can resend or revoke an invitation from the row&#39;s actions menu.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./bulk-invite-users">How do I bulk-invite users from an Excel file?</a></li><li><a href="./assign-user-to-tenant">How do I assign a user to a tenant?</a></li><li><a href="./change-user-role">How do I change a user&#39;s portal role?</a></li></ul>',9)])])}const m=t(o,[["render",s]]);export{p as __pageData,m as default};
